conn = sqlite3.connect(DB)
cur = conn.cursor()

def has_any(text, kws):
    t = text or ''
    return any(k in t for k in kws)

print("=== Fix: Move educational questions out of م15 → م17 ===")
cur.execute("SELECT id, text FROM pro_license_questions WHERE standard_num='15'")
all_15 = cur.fetchall()
nuke_ids, edu15_ids = [], []
for qid, txt in all_15:
    if has_any(txt, NUCLEAR_KW):
        nuke_ids.append(qid)
    else:
        edu15_ids.append(qid)

print(f"  م15 total: {len(all_15)}, nuclear: {len(nuke_ids)}, educational→م17: {len(edu15_ids)}")
if edu15_ids:
    cur.execute(f"UPDATE pro_license_questions SET standard_num='17', standard_name=? WHERE id IN ({','.join(map(str,edu15_ids))})", (NEW_NAMES[17],))

print("=== Fix: Move educational questions out of م16 → م18 ===")
