def insert_q(cur, txt, a, b, c, d, ans, exp, snum, sname, diff='متوسط'):
    cur.execute("""INSERT INTO pro_license_questions
        (text,option_a,option_b,option_c,option_d,answer,explanation,standard_num,standard_name,q_type,difficulty,is_active,created_at)
        VALUES (?,?,?,?,?,?,?,?,?,'mcq',?,1,?)""",
        (txt,a,b,c,d,ans,exp,str(snum),sname,diff,NOW))

